var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"새로운 메뉴를 만들어야겠어. 지금 당장.","JPN":"新しいメニューを作らねば。今すぐに。","ENG":"I have to work on a new recipe. Right now.","TWN":"必須開發新的菜單！現在立刻！"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"으응? 갑자기? 왜~ 오늘 모처럼 쉬는 날이잖아.","JPN":"うん？　いきなりどうしたのかしら。今日はせっかくのお休みじゃない。","ENG":"Hmm? Why? We’re off today.","TWN":"嗯？這麼突然？為什麼～難得今天休息欸？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"이사 오느라 지출이 크게 늘었어.","JPN":"移転のせいで出費が大幅に増えたからな。","ENG":"It was very costly to move to this place.","TWN":"搬家花太多錢了。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"이렇게라도 하지 않으면 금방 적자날 거야.","JPN":"こうでもしないとすぐに赤字になる。","ENG":"If we don’t work hard, we’ll soon end up in the red.","TWN":"不趕快想想辦法的話會出現赤字的。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"그걸 바라는 건 아니겠지? 매니저?","JPN":"それは本望じゃないだろう、マネージャー？","ENG":"Or is that what you want, supervisor?","TWN":"你應該也不希望變成這樣吧？經理？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"왜 또 이렇게 심통이실까?","JPN":"どうしてこんなにご機嫌斜めなのかしら？","ENG":"Why are you being mean again?","TWN":"幹嘛又這樣咄咄逼人？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"……네가 새 메뉴 개발을 안 하니까 그렇지!","JPN":"……エヴリンが新しいメニューを考えないからだろう！","ENG":"Because you’re not working on the new recipe!","TWN":"……都怪你不開發新菜單。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"그렇지만 난 카페에서도 장보기며 재료 손질이며 요리며 음료 제조며 서빙이며 꼬맹이들이 청소하고 난 곳들 청소하는 거며 회계 장부 작성이며 약물 연구까지 해야 해서","JPN":"だって、私はカフェの買い出しや食材の仕込み、料理、飲み物づくり、配膳に加えて、\\nあの子たちが掃除した所のやり直しや経理業務、薬品研究までしないといけないから","ENG":"But I shop for the cooking ingredients, prepare them, fix drinks, serve customers, clean up after the kids’ mess, write in the ledger, and research on my potions...","TWN":"因為我要負責採買、備料、出菜、做飲料、招待客人，還要把她們打掃過的地方再打掃一次，收店後要作帳，還要研究藥水，"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":" 너~무 바쁜걸?","JPN":"と～っても忙しいのよ？","ENG":" I’m just TOO busy.","TWN":"很～忙欸？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"……참. 그렇겠네.","JPN":"……ああ、そうだったな。","ENG":"Okay... I see.","TWN":"……哼，我就知道你會這麼說。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"뭐, 어쩔 수 없지. 내가 신 메뉴를 개발하는 수밖에.","JPN":"まあ、しょうがない。妾が新メニューを作るしかないな。","ENG":"Well then, I’ll have to work on the new recipe myself.","TWN":"那沒辦法，只好我自己來開發新菜單囉。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"네가? 라우라 네가 메뉴 개발을 하겠다고? 흐음. 그거 아무나 하는 거 아닌데.","JPN":"あなたが？　ラウラが新メニューを作るの？　うーん、誰にでもできることじゃないけれど……","ENG":"You? Working on the new recipe? Hmm, not just anyone can do it, you know.","TWN":"你？你說你要開發菜單？呵呵，這可不是誰都能做的。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"네 생각처럼 그렇게 쉽게 뚝딱 만들어지는 게 아니란 말씀~","JPN":"思ってるほど、そう簡単に作れるものじゃないのよ～。","ENG":"It's not something you can do with a flick of your finger.","TWN":"沒你想像中那麼簡單～"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"왜 이래! 그딴 건 나한테 식은 죽 먹기라고.","JPN":"バカにするな！　それくらい、妾にとって朝飯前だ。","ENG":"Hah! It’s a piece of cake for me.","TWN":"你幹嘛！這對我來說易如反掌啦！"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"감탄할 만한 신 메뉴를 만들어서 네가 요리 권한을 나한테 아예 바치도록 만들어 줄게.","JPN":"エヴリンが料理の権限を譲りたくなるような、すごい新メニューを作ってやる。","ENG":"I’ll come up with an amazing new recipe, so good that you’ll want me to do all the cooking.","TWN":"我會開發出讓你驚訝到說不出話來的新菜單，厲害到讓你交出主廚的寶座。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"그건 지금이라도 당장 넘길 수 있어. 부디 가져가 줄래?","JPN":"それなら今すぐにでも譲ってあげるわよ。お願いだから、もらってくれる？","ENG":"I can do that right away. Please do take my place.","TWN":"什麼寶座你要就給你吧，拜託你現在就拿去好嗎？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"……오늘 부엌은 내가 차지할 거니까, 아무도 들어오지 마!!","JPN":"……今日は妾がキッチンを貸切る！　誰も入るなよ！！","ENG":"... I’m using the kitchen today, and I don’t want anyone to come in!","TWN":"……今天廚房是我專用的，任何人都不准進來！！"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"그러고 들어가서 아직도 부엌에 콕 틀어박혀 있어.","JPN":"それからずっと、キッチンに閉じこもってるのよ。","ENG":"And she’s still in the kitchen.","TWN":"說完後到現在還沒出來。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"으응. 그렇게 된 거군요?","JPN":"なるほど、そうだったんですね。","ENG":"I see.","TWN":"喔喔～原來是這樣。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"라우라가 잘 만들고 있을까요?","JPN":"ラウラ、うまくいっているのかな。","ENG":"Do you think Laura is doing okay?","TWN":"不知道蘿拉還順利嗎？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"……먹을 수 있는 음식으로만 나오면 좋겠네.","JPN":"……食べられる状態なら、上出来でしょうね。","ENG":"... I just hope she comes up with something edible.","TWN":"……我只希望能吃就好。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L27_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"빨리 맛보고 싶다! 아주 따끔하게 평가해줘야지! 엣헴.","JPN":"早く食べてみたいな！　超辛口に評価にしてやる！　えっへん。","ENG":"I would love to taste her new recipes! I will be a strict judge! Ahem!","TWN":"真想趕快試吃！我要當毒舌評審！嘿嘿～"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L28_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"뭘 따끔하게 평가해?","JPN":"何を超辛口にするだって？","ENG":"And you’re judging what?","TWN":"你想當毒舌評審？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"!! 라, 라우라. 언제 나왔어?","JPN":"はっ！！　ラ、ラウラ。いつの間に？","ENG":"L-Laura! When did you come out?","TWN":"蘿…蘿拉，你什麼時候出來的？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"방금. 이건 막 만든 요리들.","JPN":"たった今だ。さあ、妾が作った料理だ。","ENG":"Just now. Here are the dishes I made.","TWN":"剛才，我剛做完這些。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"와아! 생각보다 엄청 먹음직스러워 보여!","JPN":"わぁ！　思ったよりずっと美味しそうだよ！","ENG":"Wow, they look great!","TWN":"哇哇！看起來比想像中美味欸！"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"먹어봐도 돼~?","JPN":"食べてもいい～？","ENG":"Can I try?","TWN":"可以試吃看看嗎～？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"뭐, 그러던가……. 네가 굳이 먹겠다는데 막을 필요는 없겠지.","JPN":"まあ、いいが……ユナが食べるというなら、止める理由も特になかろう。","ENG":"Whatever... I’m not stopping you if you want.","TWN":"想吃就吃吧……既然你這麼想吃我也沒必要攔你。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"흐음……?","JPN":"ふむ……？","ENG":"Huh?","TWN":"嗯……？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"잘 먹겠습니다아! 하압.","JPN":"いただきまあす！　はむっ。","ENG":"Thank you! *Nom*","TWN":"那我要吃囉！啊～～"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"맛있는데?! 이거 이름이 뭐……","JPN":"おいしい！？　これ、名前は何て……","ENG":"Oh, it’s great! What’s it called...","TWN":"好吃欸？！這叫什麼……"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":" 개굴?","JPN":"ケロ？","ENG":" Ribbit?","TWN":"呱呱？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"어머. 그렇게 막 갖다 붙일 정도로 형편없는 맛이니?","JPN":"あら、そんなふざけた反応をするほどひどい味なの？","ENG":"Oh, is it that bad?","TWN":"天啊，是難吃到無法用言語形容嗎？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"유나도 꽤나 짓궂은 면이 있었네?","JPN":"ユナにも案外お茶目な面があったのね？","ENG":"Yuna, I didn’t know you had such a wicked sense of humor.","TWN":"沒想到尤娜這麼會羞辱人？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"개굴?","JPN":"ケロ？","ENG":"Ribbit?","TWN":"呱呱？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":" ……개, 개굴?! 개굴개굴?!?!","JPN":" ……ケ、ケロ！？　ケロケロ！？！？","ENG":" ...Ribbit? Ribbit? Ribbit, ribbit?!","TWN":" ……呱呱？！呱呱呱呱？！？！"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"……쳇. 이번에도 실패군.","JPN":"……チッ！　今回も失敗か。","ENG":"Dang, I failed again.","TWN":"……嘖，看來這次也失敗了。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"개구울?!","JPN":"ケローッ！？","ENG":"RIBBIT?!","TWN":"呱呱呱？！"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"으응?","JPN":"んん？","ENG":"Huh?","TWN":"嗯？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"설마 개구리 소리밖에 못 내는 저주인가?","JPN":"まさか、ケロケロしか言えなくなる呪い？","ENG":"Is this some sort of froggy curse?","TWN":"難道是只能發出青蛙叫聲的咒語？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"개굴개구울!!","JPN":"ケロケローッ！！","ENG":"RIBBIT, RIBBIT!","TWN":"呱呱呱呱呱！！"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"유나한테 저주를 건 거야? 너무한걸.","JPN":"まさかユナに呪いをかけたの？　ひどいわね。","ENG":"You cursed Yuna? That’s just too much.","TWN":"你對尤娜下咒嗎？太過分了吧？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"이번엔 혹시 성공했을까 싶었지. 내가 일부러 저주를 건 건 아니라고.","JPN":"もしかしたら今回は成功したかと思ったのだ。わざと呪いをかけたわけではない。","ENG":"I thought it was going to work this time. That wasn’t intentional.","TWN":"我以為這次會成功的嘛，又不是故意的。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"개굴! 개굴개굴개구…… 무해!","JPN":"ケロ！　ケロケロケ……どい！","ENG":"Ribbit! Ribbit, ribbit, ribbit... too much!","TWN":"呱呱！呱呱呱呱……過分！"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":" 앗. 목소리 돌아왔다!","JPN":"あっ、声が戻った！","ENG":" Oh, my voice is back!","TWN":"喔？我的聲音回來了！"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"다행이야. 효과가 그리 길진 않아서.","JPN":"効果がそこまで長くなくてよかったわ。","ENG":"It was fortunate that the curse didn’t last long.","TWN":"幸好咒語的時效不長。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"여기서 기다리고 있어. 다음 요리는 제대로 만들어올 테니까.","JPN":"ここで待ってろ。次はちゃんとした料理を作ってくるから。","ENG":"Wait here. I’ll go get the right one this time.","TWN":"你們在這裡等我，下一道料理一定沒問題的。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"절대, 절대 부엌엔 들어오지 말고!","JPN":"絶対に、何があっても、キッチンには入るなよ！","ENG":"Remember, the kitchen is off-limits!","TWN":"千千萬萬，不能進來廚房喔！"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"흐아…… 또 먹어야 하다니…….","JPN":"うわあ……また食べなきゃいけないのかな……","ENG":"No... I have to eat it again?","TWN":"呃……又要試吃喔……"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"요리에 왜 저주가 실리는 걸까? 보지 말라니까 더 수상하네?","JPN":"どうして料理に呪いがかかるのかしら。見るなって言われたら余計見たくなるわね。","ENG":"Why is her dish cursed? Why doesn’t she want us to come into the kitchen?","TWN":"為什麼要對料理下咒語？不讓人看反而更可疑呢？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L11_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"안 되겠다. 제가 가서 몰래 훔쳐보고 올게요!","JPN":"ダメだ、私がこっそり見てきます！","ENG":"I can’t just sit around and wait. I will go to the kitchen and take a peek!","TWN":"不管啦！我要溜進去偷看一下！"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L15_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"어땠니?","JPN":"どうだった？","ENG":"How did it go?","TWN":"怎麼樣？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"……있죠. 우리 부엌에 가마솥이 있었나요? 아주 커다랗고 새까만 거요!","JPN":"……あのう、うちのカフェに大釜なんてありましたっけ？\\nものすごく大きくて真っ黒なやつ！","ENG":"Um... Did we have a large cauldron in our kitchen? A very big and dark one?","TWN":"……那個，我們廚房裡原本有大鐵鍋嗎？黑黑的大鐵鍋！"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"우리 카페에 그런 건 없는데?","JPN":"うちのカフェには無いと思うけど？","ENG":"No, we didn’t have a cauldron in our cafe.","TWN":"沒有啊？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L18_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"라우라가 거기에 꿈틀거리는 걸 넣으면서 꼭 나쁜 마녀처럼 국자로 휘휘~ 젓고 있었어요!","JPN":"ラウラがまるで悪い魔女みたいに、大釜にぐにゃぐにゃしたものを入れて、\\nお玉でグルグル混ぜてましたよ！","ENG":"I saw Laura putting something squirming into the cauldron and stirring it with a long ladle, like some evil witch.","TWN":"蘿拉把在蠕動的東西放到鍋裡，然後像壞巫婆一樣拿著湯勺在那邊攪拌！"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L19_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"대체 뭘 만들고 있는 거지?!","JPN":"いったい何を作ってるんだろう！？","ENG":"What the heck is she cooking?","TWN":"她到底在煮什麼？！"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L20_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"훌륭한 요리지. ……뭐, 약간의 문제는 있지만.","JPN":"立派な料理だ……まあ、若干、問題はあるが。","ENG":"A tasty dish. With a slight problem.","TWN":"當然是好吃的囉……雖然中間有出點差錯。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"!! 또 언제 나왔어!","JPN":"げっ！　またいつの間に！！","ENG":"ARGH! When did you come out?","TWN":"！！你怎麼又突然冒出來！"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"시끄럽고, 이거나 먹어 봐.","JPN":"うるさいな。それよりこれを食べてみろ。","ENG":"Shut up and try this dish.","TWN":"吵什麼吵，來吃吃看這個。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"……안 먹고 싶어어.","JPN":"……食べたくないよー。","ENG":"But I don’t want to.","TWN":"……我不想吃。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"이번엔 괜찮을지도 몰라. 특별히 조심했다고.","JPN":"今回はいけるかもしれない。慎重に慎重を重ねたからな。","ENG":"You’ll be okay, probably. I did pay attention this time.","TWN":"這次應該沒問題啦，我有特別小心一點。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"……별로 그래 보이진 않던데. 막, 마법 주문 중얼거리고 그러지 않았어?","JPN":"……あまりそんな風には見えなかったけど。ほら、魔法の呪文を唱えたりしてたでしょ？","ENG":"You didn’t seem very attentive. Also I heard you chanting a spell.","TWN":"……看起來不像欸？你剛是在唸咒語吧？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"뭐야. 그새 훔쳐본 거야? 나참. 말도 더럽게 안 들어, 하여튼.","JPN":"なんだ、さてはのぞき見したな？　まったく、言うことを聞かない奴だな。","ENG":"What, you took a peek? I told you not to come in! You never listen to me, do you?","TWN":"什麼？你剛跑進來偷看嗎？討厭，耳朵真的很硬欸！"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_HATE"}}}},{"id":"L27_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"내가 주문을 왜 외워. 레시피 안 까먹게 중얼거리고 있었을 뿐이야.","JPN":"呪文なんか唱えるわけないだろう。レシピを忘れないように読み上げていただけだ。","ENG":"I wasn’t chanting a spell. I was murmuring the recipe so that I wouldn't forget.","TWN":"我幹嘛要背咒語？我是在背食譜。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"그럼 요리에 저주가 왜 실리는 건데?!","JPN":"じゃあ、どうして料理に呪いがかかるの！？","ENG":"Then why is your dish cursed?","TWN":"那料理為什麼會被下咒語？！"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"어머. 라우라 네가 요리에 직접 저주 건 게 아니야?","JPN":"あら、ラウラ。あなたが料理に呪いをかけてたんじゃないの？","ENG":"Oh, Laura. Are you saying that you didn’t curse your dish?","TWN":"天啊，蘿拉，所以不是你對料理下咒語的嗎？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"당연하지. 신 메뉴 개발 중인데 저주를 걸어서 뭐하게?","JPN":"もちろんだ。手間暇かけて新メニューを開発しているのに、呪いなんてかけるわけないだろう。","ENG":"Of course not. I’m working on a new recipe. Why would I curse my own dish?","TWN":"當然不是，我是在開發新菜單，下咒語要幹嘛？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"하아. 영문을 모르니까 더 답답하네.","JPN":"はあ……いったいなぜだ。もどかしいな。","ENG":"Oh, bummer. I don’t know what I’m doing wrong.","TWN":"嘖，真是莫名其妙。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"흐음. 아무래도 안 하던 걸 해서 그런가? 너도 모르게 마력이 실리는 모양인데.","JPN":"ふーん。慣れないことをしたからかしら。知らないうちに魔力が込められていたのかもね。","ENG":"Maybe it’s because you’re not used to cooking. Maybe you’re using magic without realizing it.","TWN":"嗯，那應該是因為第一次吧？或許是在你不知情的情況下被施加魔法的。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"마치 내가 너 몰래 음료에 약물을 타듯이 말이야. 후후.","JPN":"まるで私があなたには内緒で、飲み物に薬品を混ぜてるみたいにね、フフフッ。","ENG":"You know, like how I use potions when I make your drink.","TWN":"就像我會把藥水偷偷加在你的飲料裡一樣，呵呵。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"……그런 짓 좀 그만 하라니까.","JPN":"……そういうのはもうやめろ。","ENG":"... I told you not to do that.","TWN":"……拜託你別再加那些有的沒的了。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"아무튼. 이제 시식은 그만하는 게 낫지 않겠어? 유나 저러다 큰일날 것 같은데?","JPN":"とにかく、もう試食はやめたほうがいいんじゃない？　あの調子じゃあ、ユナが大変なことになりそうよ？","ENG":"Anyway, I think you should stop testing out your recipes on us. It’s not good for Yuna.","TWN":"言歸正傳，這次的試吃就先到此為止吧？我怕尤娜再試吃下去會出事。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"하아…… 알았어. 어쩔 수 없지.","JPN":"はあ……わかった。仕方ないな。","ENG":"*Sigh* Okay. I will stop.","TWN":"哀哀……好吧，就這樣吧。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"이번 요리 개발은 여기서 끝내야…….","JPN":"今回の新メニュー開発はここまでに……","ENG":"My new recipe research is over for now...","TWN":"這次開發新菜單宣告失……"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"……플루토?!","JPN":"……プルートー！？","ENG":"... Pluto?!","TWN":"……布魯托？！"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"CAT_STREGA_NULL_NULL","text":{"KOREA":"냐옹~ 냠!","JPN":"にゃあ～あむ！","ENG":"Meow, meow. *Bite*","TWN":"喵～喵！"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"……?! 그, 그런 거 먹으면 못써! 얼른 뱉어내!!","JPN":"……！？　そ、そんなもの食べちゃダメだ！　今すぐ吐き出せ！！","ENG":"No! Don’t eat that! Spit it out!","TWN":"……？！那個不能吃！快吐出來！！"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"CAT_STREGA_NULL_NULL","text":{"KOREA":"냐옹? 냐아옹. 냠.","JPN":"にゃあ？　にゃああ、あむ。","ENG":"Meow? Meooow. *Swallow*","TWN":"喵喵？喵喵喵。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"어, 어떡해! 내가 아까 먹다 남긴 것들도 먹고 있어!","JPN":"ど、どうしよう！　私の食べ残しまで食べちゃったよ！","ENG":"Oh no! Pluto is eating the previous dish as well!","TWN":"怎…怎麼辦！牠現在在吃我剛吃剩下的欸！"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"더 큰일나기 전에 빨리 치우자!!","JPN":"もっと大変なことになる前に、早く片付けよう！！","ENG":"We have to clean it up before something really bad happens!","TWN":"趁牠還沒出事趕快清掉吧！！"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"……잠깐.","JPN":"……ちょっと待て。","ENG":"... Wait.","TWN":"……先等一下。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L1_1","type":"dialog","speaker":"CAT_STREGA_NULL_NULL","text":{"KOREA":"냐암. 냐오옹~","JPN":"にゃあむ。にゃああ～。","ENG":"Meow. Meooow.","TWN":"喵喵，喵喵喵～"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"엄청 맛있게 먹네……? 접시까지 싹싹 핥아 먹고 있잖아. 설거지 안 해도 되겠어.","JPN":"とても美味しそうに食べてない……？　お皿までペロペロ舐めてるね。洗い物しなくて済むかも。","ENG":"Pluto is actually enjoying the meal. He’s licking the plate so clean that we don’t have to wash it.","TWN":"牠好像很喜歡……？還舔盤子呢，都不用洗碗了。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"멀쩡한데? ……저주가 깃들지 않았어.","JPN":"何ともないのか？　……呪いはかかっていない。","ENG":"Pluto is fine. He’s not cursed.","TWN":"牠好像沒事？……咒語好像沒效。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L7_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"흐음……. 이거 혹시……?","JPN":"うーん……これはもしや……？","ENG":"Hmm... maybe...","TWN":"嗯……難道……？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"자아~ 여러분이 기다리시던 반려동물 한정 신 메뉴 나왔습니다.","JPN":"さあ～皆さんお待ちかねのペット限定の新メニューです。","ENG":"Thank you for waiting! This is our new dish for pets.","TWN":"來喔～大家期待的寵物限定菜單來囉。"},"stage":{"bg":"CITY_CENTER1","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"줄 서주세요!","JPN":"こちらにお並びくださいね！","ENG":"Please stay in line!","TWN":"請排隊！"},"stage":{"bg":"CITY_CENTER1","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"거기 멍멍이! 새치기하면 안 돼! 요리 안 준다, 너?!","JPN":"そこのわんこ！　割り込んじゃダメでしょ！　お料理あげないよ！？","ENG":"Hey, doggo! No cutting in, okay? We won’t serve you if you cut!","TWN":"小狗狗！不可以插隊！插隊沒得吃喔！"},"stage":{"bg":"CITY_CENTER1","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L17_1","type":"dialog","speaker":"CHILDREN_BARCODE_TWO_DOG","text":{"KOREA":"끼잉…….","JPN":"クゥーン……","ENG":"*Whimper*","TWN":"凹嗚……"},"stage":{"bg":"CITY_CENTER1","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_ANIMAL_D3"},{"id":"L18_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"와. 반려인들 반응이 아주 열렬하네.","JPN":"わあ、飼い主さんたちに大好評ね。","ENG":"Wow, the pet owners are loving it!","TWN":"哇喔，反應非常熱烈呢。"},"stage":{"bg":"CITY_CENTER1","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"적자만 면한 게 아니라 매출도 쑥쑥 오르겠는걸♪","JPN":"これなら赤字解消だけじゃなくて、売上もグングン伸びそう♪","ENG":"Our profits will skyrocket! ♪","TWN":"不只順利解除赤字的危機，收入也增加好多呢♪"},"stage":{"bg":"CITY_CENTER1","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"라우라. 반응도 좋은데, 신 메뉴 개발 더 할 거야?","JPN":"ラウラ。評判もいいし、また新メニューを開発したら？","ENG":"Laura, it’s sensational. Are you going to create anything else?","TWN":"蘿拉，反應這麼好，你要再多開發幾道嗎？"},"stage":{"bg":"CITY_CENTER1","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"아니. 이제 끝이야. 더는 안 해.","JPN":"いや、これでおしまいだ。これ以上はもうやらん。","ENG":"No, I’m done with it. I’m not making any more recipes.","TWN":"才不要，到此為止。"},"stage":{"bg":"CITY_CENTER1","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"앗! 안돼! 나 방금 코뿔소 전용 요리 주문받고 왔단 말이야.","JPN":"あっ、ダメよ！　今さっきサイ専用料理の注文を受けたんだから。","ENG":"Why not? I just received an order for a Rhino!","TWN":"不行啦！我剛才收到客人要點犀牛專屬料理欸！"},"stage":{"bg":"CITY_CENTER1","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"절대 안 해. 취소시켜.","JPN":"絶対にやらない。キャンセルさせろ。","ENG":"I’m not cooking anymore. Cancel it.","TWN":"沒辦法，取消餐點。"},"stage":{"bg":"CITY_CENTER1","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"내가 이렇게 간절히 부탁해도~?","JPN":"私がこんなに心を込めてお願いしても～？","ENG":"Even when I beg you like this?","TWN":"人家這麼認真拜託你欸～？"},"stage":{"bg":"CITY_CENTER1","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"취소시켜!!","JPN":"キャンセルさせろ！！","ENG":"CANCEL IT!","TWN":"取消！！"},"stage":{"bg":"CITY_CENTER1","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_HATE"},"R":null}}}]`);export{e as default};